AOS.init();let searchToggle=document.querySelector(".search-active"),headerSearch=document.querySelector(".header-search"),searchInput=headerSearch.querySelector("input"),lastScroll=(searchToggle.addEventListener("click",()=>{headerSearch.classList.toggle("open")||(searchInput.value="")}),0),header=document.querySelector("header");window.addEventListener("scroll",()=>{var e=window.scrollY;e>lastScroll?header.classList.add("hide"):header.classList.remove("hide"),lastScroll=e});